#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        for(int i=1;i<=N;i++){
            if(i>1) printf(" ");
            printf("%d", 2*i);
        }
        if(T) printf("\n");
    }
    return 0;
}

